import{_ as e,c as a,o as l,ao as i}from"./chunks/framework.DOhyS95j.js";const c=JSON.parse('{"title":"一元线性回归预测体重","description":"","frontmatter":{},"headers":[],"relativePath":"code/ai/机器学习/03_线性回归/线性回归计算过程.md","filePath":"code/ai/机器学习/03_线性回归/线性回归计算过程.md"}'),r={name:"code/ai/机器学习/03_线性回归/线性回归计算过程.md"};function d(n,t,s,$,o,h){return l(),a("div",null,t[0]||(t[0]=[i('<h1 id="一元线性回归预测体重" tabindex="-1">一元线性回归预测体重 <a class="header-anchor" href="#一元线性回归预测体重" aria-label="Permalink to &quot;一元线性回归预测体重&quot;">​</a></h1><p>我们用<strong>最小二乘法</strong>，严格按照公式一步步算出最优的 $w$（斜率）和 $b$（截距|偏置），再代入公式预测身高176cm的体重，全程和代码结果完全对应。</p><hr><h2 id="一、核心公式-最小二乘法" tabindex="-1">一、核心公式（最小二乘法） <a class="header-anchor" href="#一、核心公式-最小二乘法" aria-label="Permalink to &quot;一、核心公式（最小二乘法）&quot;">​</a></h2><h3 id="_1-斜率-w-公式" tabindex="-1">1. 斜率 $w$ 公式 <a class="header-anchor" href="#_1-斜率-w-公式" aria-label="Permalink to &quot;1. 斜率 $w$ 公式&quot;">​</a></h3><p>$$ w = \\frac{n\\sum_{i=1}^n x_i y_i - \\sum_{i=1}^n x_i \\cdot \\sum_{i=1}^n y_i}{n\\sum_{i=1}^n x_i^2 - \\left(\\sum_{i=1}^n x_i\\right)^2} $$</p><h3 id="_2-截距-偏置-b-公式" tabindex="-1">2. 截距|偏置 $b$ 公式 <a class="header-anchor" href="#_2-截距-偏置-b-公式" aria-label="Permalink to &quot;2. 截距|偏置 $b$ 公式&quot;">​</a></h3><p>$$ b = \\bar{y} - w \\cdot \\bar{x} $$ 其中 $\\bar{x} = \\frac{1}{n}\\sum x_i$ 是身高均值，$\\bar{y} = \\frac{1}{n}\\sum y_i$ 是体重均值。</p><h3 id="_3-预测公式-斜率w-测试的值x-偏置b" tabindex="-1">3. 预测公式:(斜率w*测试的值x+偏置b) <a class="header-anchor" href="#_3-预测公式-斜率w-测试的值x-偏置b" aria-label="Permalink to &quot;3. 预测公式:(斜率w*测试的值x+偏置b)&quot;">​</a></h3><p>$$ \\hat{y} = w x + b $$</p><hr><h2 id="二、数据准备-n-5-个训练样本" tabindex="-1">二、数据准备（$n=5$ 个训练样本） <a class="header-anchor" href="#二、数据准备-n-5-个训练样本" aria-label="Permalink to &quot;二、数据准备（$n=5$ 个训练样本）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">编号</th><th style="text-align:left;">身高 $x$ (cm)</th><th style="text-align:left;">体重 $y$ (kg)</th><th style="text-align:left;">$x_i y_i$</th><th style="text-align:left;">$x_i^2$</th></tr></thead><tbody><tr><td style="text-align:left;">1</td><td style="text-align:left;">160</td><td style="text-align:left;">56.3</td><td style="text-align:left;">$160 \\times 56.3 = 9008$</td><td style="text-align:left;">$160^2 = 25600$</td></tr><tr><td style="text-align:left;">2</td><td style="text-align:left;">166</td><td style="text-align:left;">60.6</td><td style="text-align:left;">$166 \\times 60.6 = 10059.6$</td><td style="text-align:left;">$166^2 = 27556$</td></tr><tr><td style="text-align:left;">3</td><td style="text-align:left;">172</td><td style="text-align:left;">65.1</td><td style="text-align:left;">$172 \\times 65.1 = 11197.2$</td><td style="text-align:left;">$172^2 = 29584$</td></tr><tr><td style="text-align:left;">4</td><td style="text-align:left;">174</td><td style="text-align:left;">68.5</td><td style="text-align:left;">$174 \\times 68.5 = 11919$</td><td style="text-align:left;">$174^2 = 30276$</td></tr><tr><td style="text-align:left;">5</td><td style="text-align:left;">180</td><td style="text-align:left;">75</td><td style="text-align:left;">$180 \\times 75 = 13500$</td><td style="text-align:left;">$180^2 = 32400$</td></tr><tr><td style="text-align:left;"><strong>求和</strong></td><td style="text-align:left;">$\\sum x_i = 852$</td><td style="text-align:left;">$\\sum y_i = 325.5$</td><td style="text-align:left;">$\\sum x_i y_i = 55683.8$</td><td style="text-align:left;">$\\sum x_i^2 = 145416$</td></tr></tbody></table><hr><h2 id="三、分步计算参数-w-和-b" tabindex="-1">三、分步计算参数 $w$ 和 $b$ <a class="header-anchor" href="#三、分步计算参数-w-和-b" aria-label="Permalink to &quot;三、分步计算参数 $w$ 和 $b$&quot;">​</a></h2><h3 id="步骤1-计算均值" tabindex="-1">步骤1：计算均值 <a class="header-anchor" href="#步骤1-计算均值" aria-label="Permalink to &quot;步骤1：计算均值&quot;">​</a></h3><p>$$ \\bar{x} = \\frac{\\sum x_i}{n} = \\frac{852}{5} = 170.4 $$ $$ \\bar{y} = \\frac{\\sum y_i}{n} = \\frac{325.5}{5} = 65.1 $$</p><h3 id="步骤2-计算斜率-w" tabindex="-1">步骤2：计算斜率 $w$ <a class="header-anchor" href="#步骤2-计算斜率-w" aria-label="Permalink to &quot;步骤2：计算斜率 $w$&quot;">​</a></h3><p>代入公式： $$ \\begin{align*} w &amp;= \\frac{n\\sum x_i y_i - \\sum x_i \\cdot \\sum y_i}{n\\sum x_i^2 - (\\sum x_i)^2} \\ &amp;= \\frac{5 \\times 55683.8 - 852 \\times 325.5}{5 \\times 145416 - 852^2} \\ &amp;= \\frac{278419 - 277326}{727080 - 725904} \\ &amp;= \\frac{1093}{1176} \\ &amp;\\approx 0.92942177 \\end{align*} $$ ✅ 和代码 <code>model.coef_ = [0.92942177]</code> 完全一致。</p><h3 id="步骤3-计算截距-偏置-b" tabindex="-1">步骤3：计算截距|偏置 $b$ <a class="header-anchor" href="#步骤3-计算截距-偏置-b" aria-label="Permalink to &quot;步骤3：计算截距|偏置 $b$&quot;">​</a></h3><p>代入公式 $b = \\bar{y} - w \\cdot \\bar{x}$： $$ \\begin{align*} b &amp;= 65.1 - 0.92942177 \\times 170.4 \\ &amp;= 65.1 - 158.373469 \\ &amp;= -93.273469 \\end{align*} $$ ✅ 和代码 <code>model.intercept_ = -93.27346938775517</code> 完全一致。</p><hr><h2 id="四、预测身高176cm的体重" tabindex="-1">四、预测身高176cm的体重 <a class="header-anchor" href="#四、预测身高176cm的体重" aria-label="Permalink to &quot;四、预测身高176cm的体重&quot;">​</a></h2><p>将 $x=176$ 代入方程： $$ \\begin{align*} \\hat{y} &amp;= 0.92942177 \\times 176 + (-93.273469) \\ &amp;= 163.57823152 - 93.273469 \\ &amp;= 70.30476252 \\end{align*} $$</p><hr><h2 id="五、最终结论" tabindex="-1">五、最终结论 <a class="header-anchor" href="#五、最终结论" aria-label="Permalink to &quot;五、最终结论&quot;">​</a></h2><p>✅ 身高176cm对应的<strong>预测体重约为 70.30kg</strong>，和代码手动计算、模型预测结果完全一致。</p><hr><h3 id="💡-关键补充" tabindex="-1">💡 关键补充 <a class="header-anchor" href="#💡-关键补充" aria-label="Permalink to &quot;💡 关键补充&quot;">​</a></h3><p>1<strong>参数含义</strong> - $w \\approx 0.93$：身高每增加1cm，体重平均增加约0.93kg； - $b \\approx -93.27$：是线性方程的截距，仅为数学拟合项，无实际物理意义。</p><p>2<strong>代码验证</strong> 你的代码逻辑完全正确，手动计算和模型预测结果一致，说明模型拟合成功。</p><hr>',32)]))}const m=e(r,[["render",d]]);export{c as __pageData,m as default};
